class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        res = []
        for digits in range(len(str(low)), len(str(high))+1):
            for first_digit in range(1, 10):
                num = 0
                for i in range(digits):
                    num = num * 10 + (first_digit + i)
                if low <= num <= high:
                    res.append(num)
        return res
